class NotificationService {
    private final Logger logger = Logger.getLogger("NotificationService");

    void send(String type, String message, String recipient) {
        Notification notification;

        // This switch is the PROBLEM — duplicated in 5 services
        switch (type) {
            case "email":
                notification = new EmailNotification("smtp.company.com", 587, true);
                break;
            case "sms":
                notification = new SMSNotification("TWILIO_KEY", "us-east-1");
                break;
            case "push":
                notification = new PushNotification("FCM_SERVER_KEY", Priority.HIGH);
                break;
            case "slack":
                notification = new SlackNotification("xoxb-token", "#general");
                break;
            default:
                throw new IllegalArgumentException("Unknown type: " + type);
        }

        notification.setRecipient(recipient);
        notification.send(message);
        logger.info("Sent " + type + " to " + recipient);
    }
}

