// SOLUTION: Factory extracts all creation logic
class NotificationFactory {
    static Notification create(String type) {
        switch (type) {
            case "email":  return new EmailNotification("smtp.company.com", 587, true);
            case "sms":    return new SMSNotification("TWILIO_KEY", "us-east-1");
            case "push":   return new PushNotification("FCM_SERVER_KEY", Priority.HIGH);
            case "slack":  return new SlackNotification("xoxb-token", "#general");
            default:       throw new IllegalArgumentException("Unknown type: " + type);
        }
    }
}

class NotificationService {
    private final Logger logger = Logger.getLogger("NotificationService");

    void send(String type, String message, String recipient) {
        Notification notification = NotificationFactory.create(type);
        notification.setRecipient(recipient);
        notification.send(message);
        logger.info("Sent " + type + " to " + recipient);
    }
}

