// SOLUTION: Registry pattern — zero switch, zero if-else
class NotificationFactory {
    private static final Map<String, Supplier<Notification>> registry
        = new HashMap<>();

    static {
        register("email",  () -> new EmailNotification("smtp.company.com", 587));
        register("sms",    () -> new SMSNotification("TWILIO_KEY"));
        register("push",   () -> new PushNotification("FCM_KEY"));
        register("slack",  () -> new SlackNotification("xoxb-token"));
    }

    public static void register(String type, Supplier<Notification> creator) {
        registry.put(type.toLowerCase(), creator);
    }

    public static Notification create(String type) {
        Supplier<Notification> creator = registry.get(type.toLowerCase());
        if (creator == null) {
            throw new IllegalArgumentException(
                "Unknown type: " + type + ". Registered: " + registry.keySet()
            );
        }
        return creator.get();
    }
}

